@charset "utf-8";
/* CSS Document 

TemplateMo 603 Nexaverse

https://templatemo.com/tm-603-nexaverse

*/

* {
	margin: 0;
	padding: 0;
	box-sizing: border-box;
}

:root {
	--primary: #00f0ff;
	--secondary: #ff00d4;
	--accent: #9d4edd;
	--dark-1: #0a0a12;
	--dark-2: #12121f;
	--dark-3: #1a1a2e;
	--glass-bg: rgba(255, 255, 255, 0.03);
	--glass-border: rgba(255, 255, 255, 0.08);
	--glow-cyan: rgba(0, 240, 255, 0.4);
	--glow-magenta: rgba(255, 0, 212, 0.4);
}

body {
	font-family: 'Outfit', sans-serif;
	background: var(--dark-1);
	color: #ffffff;
	overflow-x: hidden;
	min-height: 100vh;
}

/* Ambient Background */
.ambient-bg {
	position: fixed;
	top: 0;
	left: 0;
	width: 100%;
	height: 100%;
	pointer-events: none;
	z-index: 0;
	overflow: hidden;
}

.orb {
	position: absolute;
	border-radius: 50%;
	filter: blur(80px);
	animation: float 20s ease-in-out infinite;
}

.orb-1 {
	width: 600px;
	height: 600px;
	background: radial-gradient(circle, var(--glow-cyan) 0%, transparent 70%);
	top: -200px;
	left: -200px;
	animation-delay: 0s;
}

.orb-2 {
	width: 500px;
	height: 500px;
	background: radial-gradient(circle, var(--glow-magenta) 0%, transparent 70%);
	bottom: -150px;
	right: -150px;
	animation-delay: -7s;
}

.orb-3 {
	width: 400px;
	height: 400px;
	background: radial-gradient(circle, rgba(157, 78, 221, 0.3) 0%, transparent 70%);
	top: 50%;
	left: 50%;
	transform: translate(-50%, -50%);
	animation-delay: -14s;
}

@keyframes float {

	0%,
	100% {
		transform: translate(0, 0) scale(1);
	}

	25% {
		transform: translate(50px, -30px) scale(1.05);
	}

	50% {
		transform: translate(-30px, 50px) scale(0.95);
	}

	75% {
		transform: translate(-50px, -20px) scale(1.02);
	}
}

/* The Background Grid Pattern Overlay */
.grid-overlay {
	position: fixed;
	top: 0;
	left: 0;
	width: 100%;
	height: 100%;
	background-image:
		linear-gradient(rgba(255, 255, 255, 0.05) 1px, transparent 1px),
		linear-gradient(90deg, rgba(255, 255, 255, 0.05) 1px, transparent 1px);
	background-size: 80px 80px;
	pointer-events: none;
	z-index: 1;
}

/* Loading Screen */
.loading-screen {
	position: fixed;
	top: 0;
	left: 0;
	width: 100%;
	height: 100%;
	background: var(--dark-1);
	z-index: 10000;
	display: flex;
	flex-direction: column;
	justify-content: center;
	align-items: center;
	transition: opacity 0.8s ease, visibility 0.8s ease;
}

.loading-screen.hidden {
	opacity: 0;
	visibility: hidden;
}

.loader-ring {
	width: 80px;
	height: 80px;
	position: relative;
}

.loader-ring::before,
.loader-ring::after {
	content: '';
	position: absolute;
	border-radius: 50%;
	border: 2px solid transparent;
}

.loader-ring::before {
	top: 0;
	left: 0;
	right: 0;
	bottom: 0;
	border-top-color: var(--primary);
	border-right-color: var(--primary);
	animation: spin 1.2s linear infinite;
}

.loader-ring::after {
	top: 10px;
	left: 10px;
	right: 10px;
	bottom: 10px;
	border-bottom-color: var(--secondary);
	border-left-color: var(--secondary);
	animation: spin 0.8s linear infinite reverse;
}

@keyframes spin {
	to {
		transform: rotate(360deg);
	}
}

.loading-text {
	margin-top: 30px;
	font-family: 'Syne', sans-serif;
	font-size: 12px;
	letter-spacing: 4px;
	color: var(--primary);
	text-transform: uppercase;
}

/* Main Container */
.container {
	position: relative;
	z-index: 10;
	padding: 40px 20px;
	max-width: 1200px;
	margin: 0 auto;
	min-height: 100vh;
	display: flex;
	flex-direction: column;
}

/* Header */
.header {
	text-align: center;
	margin-bottom: 60px;
	opacity: 0;
	animation: fadeUp 0.8s ease-out 1s forwards;
}

@keyframes fadeUp {
	to {
		opacity: 1;
		transform: translateY(0);
	}

	from {
		transform: translateY(30px);
	}
}

.logo {
	width: 90px;
	height: 90px;
	margin: 0 auto 25px;
	position: relative;
}

.logo svg {
	width: 100%;
	height: 100%;
	filter: drop-shadow(0 0 20px var(--glow-cyan));
}

.brand-name {
	font-family: 'Syne', sans-serif;
	font-size: 52px;
	font-weight: 600;
	letter-spacing: 6px;
	margin-bottom: 12px;
	background: linear-gradient(135deg, var(--primary) 0%, #ffffff 50%, var(--secondary) 100%);
	-webkit-background-clip: text;
	-webkit-text-fill-color: transparent;
	background-clip: text;
	text-transform: uppercase;
}

.tagline {
	font-size: 13px;
	letter-spacing: 5px;
	color: rgba(255, 255, 255, 0.5);
	text-transform: uppercase;
	font-weight: 300;
}

/* Menu Grid */
.menu-grid {
	display: grid;
	grid-template-columns: repeat(3, 204px);
	gap: 25px;
	margin: 0 auto 40px;
	justify-content: center;
}

.menu-item {
	height: 170px;
	background: var(--glass-bg);
	backdrop-filter: blur(20px);
	-webkit-backdrop-filter: blur(20px);
	border: 1px solid var(--glass-border);
	border-radius: 24px;
	display: flex;
	flex-direction: column;
	justify-content: center;
	align-items: center;
	cursor: pointer;
	position: relative;
	overflow: hidden;
	opacity: 0;
	transform: translateY(30px) scale(0.9);
	transition: all 0.5s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

/* Glossy effect overlay */
.menu-item::before {
	content: '';
	position: absolute;
	top: 0;
	left: 0;
	right: 0;
	height: 50%;
	background: linear-gradient(180deg,
			rgba(255, 255, 255, 0.12) 0%,
			rgba(255, 255, 255, 0.05) 40%,
			transparent 100%);
	border-radius: 24px 24px 0 0;
	pointer-events: none;
}

/* Glow ring on hover - removed, using cleaner border style */
.menu-item::after {
	display: none;
}

.menu-item:hover {
	transform: translateY(-10px) scale(1.02);
	background: rgba(0, 240, 255, 0.08);
	border-color: var(--primary);
	box-shadow:
		0 20px 40px rgba(0, 0, 0, 0.4),
		0 0 30px rgba(0, 200, 220, 0.2);
}

.menu-item.visible {
	opacity: 1;
	transform: translateY(0) scale(1);
}

.menu-item.initial-load {
	animation: menuAppear 0.5s ease-out forwards;
}

.menu-item.initial-load:nth-child(1) {
	animation-delay: 1.1s;
}

.menu-item.initial-load:nth-child(2) {
	animation-delay: 1.2s;
}

.menu-item.initial-load:nth-child(3) {
	animation-delay: 1.3s;
}

.menu-item.initial-load:nth-child(4) {
	animation-delay: 1.4s;
}

.menu-item.initial-load:nth-child(5) {
	animation-delay: 1.5s;
}

.menu-item.initial-load:nth-child(6) {
	animation-delay: 1.6s;
}

@keyframes menuAppear {
	to {
		opacity: 1;
		transform: translateY(0) scale(1);
	}
}

/* Menu Badge - Replaces Icons */
.menu-badge {
	width: 60px;
	height: 60px;
	border-radius: 50%;
	display: flex;
	justify-content: center;
	align-items: center;
	font-family: 'Syne', sans-serif;
	font-size: 22px;
	font-weight: 700;
	margin-bottom: 15px;
	position: relative;
	background: linear-gradient(135deg,
			rgba(0, 240, 255, 0.15) 0%,
			rgba(255, 0, 212, 0.15) 100%);
	border: 1px solid rgba(255, 255, 255, 0.1);
	color: var(--primary);
	text-shadow: 0 0 20px var(--glow-cyan);
	transition: all 0.4s ease;
	overflow: hidden;
}

/* Inner glossy shine */
.menu-badge::before {
	content: '';
	position: absolute;
	top: 2px;
	left: 10%;
	right: 10%;
	height: 45%;
	background: linear-gradient(180deg,
			rgba(255, 255, 255, 0.3) 0%,
			transparent 100%);
	border-radius: 50%;
	pointer-events: none;
}

/* Animated ring */
.menu-badge::after {
	content: '';
	position: absolute;
	inset: -3px;
	border-radius: 50%;
	border: 2px solid transparent;
	border-top-color: var(--primary);
	border-right-color: rgba(0, 200, 220, 0.5);
	opacity: 0;
	transition: opacity 0.4s ease;
}

.menu-item:hover .menu-badge {
	background: linear-gradient(135deg,
			rgba(0, 240, 255, 0.2) 0%,
			rgba(0, 200, 220, 0.15) 100%);
	transform: scale(1.1);
	box-shadow: 0 0 25px rgba(0, 200, 220, 0.25);
}

.menu-item:hover .menu-badge::after {
	opacity: 1;
	animation: badgeSpin 2s linear infinite;
}

@keyframes badgeSpin {
	to {
		transform: rotate(360deg);
	}
}

.menu-title {
	font-size: 12px;
	font-weight: 400;
	letter-spacing: 3px;
	text-transform: uppercase;
	color: rgba(255, 255, 255, 0.7);
	transition: all 0.3s ease;
}

.menu-item:hover .menu-title {
	color: #ffffff;
	letter-spacing: 4px;
}

/* Content Sections */
.content-section {
	display: none;
	opacity: 0;
	padding: 80px 20px;
	position: relative;
}

.content-section.active {
	display: block;
	animation: sectionIn 0.6s ease-out forwards;
}

@keyframes sectionIn {
	from {
		opacity: 0;
		transform: translateY(40px);
	}

	to {
		opacity: 1;
		transform: translateY(0);
	}
}

/* Section Header Small */
.section-header-small {
	position: fixed;
	top: 20px;
	left: 20px;
	display: flex;
	align-items: center;
	gap: 12px;
	z-index: 100;
	background: var(--glass-bg);
	backdrop-filter: blur(20px);
	-webkit-backdrop-filter: blur(20px);
	padding: 12px 20px;
	border-radius: 50px;
	border: 1px solid var(--glass-border);
}

.small-logo {
	width: 32px;
	height: 32px;
}

.small-logo svg {
	width: 100%;
	height: 100%;
	filter: drop-shadow(0 0 10px var(--glow-cyan));
}

.small-brand h3 {
	font-family: 'Syne', sans-serif;
	font-size: 14px;
	font-weight: 600;
	letter-spacing: 2px;
	color: var(--primary);
}

.small-brand p {
	font-size: 9px;
	letter-spacing: 1px;
	color: rgba(255, 255, 255, 0.5);
	margin-top: 2px;
}

/* Back Button */
.back-btn {
	position: fixed;
	top: 20px;
	right: 20px;
	padding: 12px 24px;
	background: var(--glass-bg);
	backdrop-filter: blur(20px);
	-webkit-backdrop-filter: blur(20px);
	border: 1px solid var(--glass-border);
	border-radius: 50px;
	color: rgba(255, 255, 255, 0.8);
	font-family: 'Outfit', sans-serif;
	font-size: 13px;
	letter-spacing: 2px;
	cursor: pointer;
	transition: all 0.3s ease;
	z-index: 100;
}

.back-btn:hover {
	background: rgba(0, 240, 255, 0.1);
	border-color: var(--primary);
	color: var(--primary);
	box-shadow: 0 0 20px var(--glow-cyan);
}

/* Section Content */
.section-header {
	text-align: center;
	margin-bottom: 50px;
}

.section-title {
	font-family: 'Syne', sans-serif;
	font-size: 42px;
	font-weight: 600;
	margin-bottom: 15px;
	background: linear-gradient(135deg, var(--primary) 0%, #ffffff 50%, var(--secondary) 100%);
	-webkit-background-clip: text;
	-webkit-text-fill-color: transparent;
	background-clip: text;
}

.section-subtitle {
	font-size: 14px;
	color: rgba(255, 255, 255, 0.5);
	letter-spacing: 2px;
}

/* Glass Cards */
.glass-card {
	background: var(--glass-bg);
	backdrop-filter: blur(20px);
	-webkit-backdrop-filter: blur(20px);
	border: 1px solid var(--glass-border);
	border-radius: 20px;
	padding: 30px;
	position: relative;
	overflow: hidden;
	transition: all 0.4s ease;
}

.glass-card::before {
	content: '';
	position: absolute;
	top: 0;
	left: 0;
	right: 0;
	height: 1px;
	background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.2), transparent);
}

.glass-card:hover {
	background: rgba(255, 255, 255, 0.05);
	transform: translateY(-5px);
	box-shadow: 0 20px 40px rgba(0, 0, 0, 0.3);
}

/* ===== NEW INTRODUCTION SECTION STYLES ===== */

/* Hero Banner */
.intro-hero {
	display: grid;
	grid-template-columns: 1fr 1fr;
	gap: 60px;
	align-items: center;
	margin-bottom: 60px;
	padding: 40px 0;
}

.intro-hero-content {
	max-width: 550px;
}

.intro-badge {
	display: inline-block;
	padding: 8px 18px;
	background: rgba(0, 240, 255, 0.1);
	border: 1px solid rgba(0, 240, 255, 0.3);
	border-radius: 50px;
	font-size: 12px;
	letter-spacing: 2px;
	color: var(--primary);
	margin-bottom: 25px;
}

.intro-headline {
	font-family: 'Syne', sans-serif;
	font-size: 52px;
	font-weight: 700;
	line-height: 1.15;
	margin-bottom: 25px;
	color: #ffffff;
}

.intro-headline span {
	background: linear-gradient(135deg, var(--primary), var(--accent));
	-webkit-background-clip: text;
	-webkit-text-fill-color: transparent;
	background-clip: text;
}

.intro-subtext {
	font-size: 17px;
	line-height: 1.7;
	color: rgba(255, 255, 255, 0.6);
	margin-bottom: 35px;
}

.intro-cta-group {
	display: flex;
	gap: 15px;
}

.intro-cta-primary {
	padding: 14px 32px;
	background: var(--glass-bg);
	backdrop-filter: blur(20px);
	-webkit-backdrop-filter: blur(20px);
	border: 1px solid var(--primary);
	border-radius: 50px;
	color: var(--primary);
	font-family: 'Outfit', sans-serif;
	font-size: 14px;
	font-weight: 500;
	letter-spacing: 1px;
	cursor: pointer;
	transition: all 0.3s ease;
}

.intro-cta-primary:hover {
	background: rgba(0, 240, 255, 0.15);
	box-shadow: 0 0 25px rgba(0, 200, 220, 0.3);
	transform: translateY(-2px);
}

.intro-cta-secondary {
	padding: 14px 32px;
	background: transparent;
	border: 1px solid var(--glass-border);
	border-radius: 50px;
	color: rgba(255, 255, 255, 0.7);
	font-family: 'Outfit', sans-serif;
	font-size: 14px;
	font-weight: 500;
	letter-spacing: 1px;
	cursor: pointer;
	transition: all 0.3s ease;
}

.intro-cta-secondary:hover {
	border-color: rgba(255, 255, 255, 0.3);
	color: #ffffff;
}

/* Hero Visual */
.intro-hero-visual {
	position: relative;
	height: 400px;
	display: flex;
	justify-content: center;
	align-items: center;
}

.intro-orb {
	width: 280px;
	height: 280px;
	border-radius: 50%;
	background: radial-gradient(circle at 30% 30%, rgba(0, 240, 255, 0.3), rgba(157, 78, 221, 0.2) 50%, transparent 70%);
	filter: blur(40px);
	animation: orbPulse 4s ease-in-out infinite;
}

@keyframes orbPulse {

	0%,
	100% {
		transform: scale(1);
		opacity: 0.7;
	}

	50% {
		transform: scale(1.1);
		opacity: 1;
	}
}

.intro-floating-card {
	position: absolute;
	background: var(--glass-bg);
	backdrop-filter: blur(20px);
	-webkit-backdrop-filter: blur(20px);
	border: 1px solid var(--glass-border);
	border-radius: 14px;
	padding: 16px 22px;
	display: flex;
	align-items: center;
	gap: 12px;
	box-shadow: 0 15px 35px rgba(0, 0, 0, 0.3);
	animation: floatCard 6s ease-in-out infinite;
}

.intro-floating-card::before {
	content: '';
	position: absolute;
	top: 0;
	left: 0;
	right: 0;
	height: 50%;
	background: linear-gradient(180deg, rgba(255, 255, 255, 0.08) 0%, transparent 100%);
	border-radius: 14px 14px 0 0;
	pointer-events: none;
}

.card-icon {
	font-size: 20px;
}

.card-text {
	font-size: 13px;
	font-weight: 500;
	color: rgba(255, 255, 255, 0.9);
	letter-spacing: 0.5px;
}

.card-1 {
	top: 30px;
	left: 10%;
	animation-delay: 0s;
}

.card-2 {
	top: 50%;
	right: 5%;
	transform: translateY(-50%);
	animation-delay: -2s;
}

.card-3 {
	bottom: 30px;
	left: 20%;
	animation-delay: -4s;
}

@keyframes floatCard {

	0%,
	100% {
		transform: translateY(0);
	}

	50% {
		transform: translateY(-15px);
	}
}

.card-2 {
	animation-name: floatCardAlt;
}

@keyframes floatCardAlt {

	0%,
	100% {
		transform: translateY(-50%);
	}

	50% {
		transform: translateY(calc(-50% - 15px));
	}
}

/* Metrics Strip */
.intro-metrics {
	display: flex;
	justify-content: center;
	align-items: center;
	gap: 50px;
	padding: 40px 50px;
	background: var(--glass-bg);
	backdrop-filter: blur(20px);
	-webkit-backdrop-filter: blur(20px);
	border: 1px solid var(--glass-border);
	border-radius: 20px;
	margin-bottom: 60px;
	position: relative;
	overflow: hidden;
}

.intro-metrics::before {
	content: '';
	position: absolute;
	top: 0;
	left: 0;
	right: 0;
	height: 1px;
	background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.15), transparent);
}

.metric-item {
	text-align: center;
}

.metric-value {
	font-family: 'Syne', sans-serif;
	font-size: 42px;
	font-weight: 700;
	background: linear-gradient(135deg, var(--primary), var(--accent));
	-webkit-background-clip: text;
	-webkit-text-fill-color: transparent;
	background-clip: text;
	display: inline;
}

.metric-suffix {
	font-family: 'Syne', sans-serif;
	font-size: 28px;
	font-weight: 700;
	background: linear-gradient(135deg, var(--primary), var(--accent));
	-webkit-background-clip: text;
	-webkit-text-fill-color: transparent;
	background-clip: text;
}

.metric-label {
	display: block;
	font-size: 13px;
	color: rgba(255, 255, 255, 0.5);
	margin-top: 8px;
	letter-spacing: 1px;
}

.metric-divider {
	width: 1px;
	height: 50px;
	background: linear-gradient(180deg, transparent, rgba(255, 255, 255, 0.15), transparent);
}

/* Core Values */
.intro-values {
	display: grid;
	grid-template-columns: repeat(3, 1fr);
	gap: 25px;
	margin-bottom: 60px;
}

.value-card {
	background: var(--glass-bg);
	backdrop-filter: blur(20px);
	-webkit-backdrop-filter: blur(20px);
	border: 1px solid var(--glass-border);
	border-radius: 20px;
	padding: 35px 30px;
	position: relative;
	overflow: hidden;
	transition: all 0.4s ease;
}

.value-card::before {
	content: '';
	position: absolute;
	top: 0;
	left: 0;
	right: 0;
	height: 1px;
	background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.12), transparent);
}

.value-card:hover {
	transform: translateY(-8px);
	border-color: rgba(0, 240, 255, 0.2);
	box-shadow: 0 25px 50px rgba(0, 0, 0, 0.3);
}

.value-number {
	font-family: 'Syne', sans-serif;
	font-size: 48px;
	font-weight: 700;
	color: rgba(0, 240, 255, 0.15);
	margin-bottom: 15px;
	line-height: 1;
}

.value-card h3 {
	font-family: 'Syne', sans-serif;
	font-size: 20px;
	font-weight: 600;
	color: var(--primary);
	margin-bottom: 12px;
}

.value-card p {
	font-size: 14px;
	line-height: 1.7;
	color: rgba(255, 255, 255, 0.6);
}

/* Tech Stack */
.intro-tech {
	text-align: center;
}

.tech-label {
	font-size: 12px;
	letter-spacing: 3px;
	color: rgba(255, 255, 255, 0.4);
	text-transform: uppercase;
	margin-bottom: 20px;
}

.tech-marquee {
	overflow: hidden;
	position: relative;
	padding: 20px 0;
}

.tech-marquee::before,
.tech-marquee::after {
	content: '';
	position: absolute;
	top: 0;
	bottom: 0;
	width: 100px;
	z-index: 2;
	pointer-events: none;
}

.tech-marquee::before {
	left: 0;
	background: linear-gradient(90deg, var(--dark-1), transparent);
}

.tech-marquee::after {
	right: 0;
	background: linear-gradient(-90deg, var(--dark-1), transparent);
}

.tech-track {
	display: flex;
	gap: 40px;
	animation: marquee 20s linear infinite;
}

@keyframes marquee {
	0% {
		transform: translateX(0);
	}

	100% {
		transform: translateX(-50%);
	}
}

.tech-item {
	font-family: 'Syne', sans-serif;
	font-size: 18px;
	font-weight: 500;
	color: rgba(255, 255, 255, 0.3);
	white-space: nowrap;
	transition: color 0.3s ease;
}

.tech-item:hover {
	color: var(--primary);
}

/* Services Row Layout */
.services-list {
	display: grid;
	grid-template-columns: repeat(2, 1fr);
	gap: 20px;
	margin-top: 30px;
}

.service-row {
	background: var(--glass-bg);
	backdrop-filter: blur(20px);
	-webkit-backdrop-filter: blur(20px);
	border: 1px solid var(--glass-border);
	border-radius: 20px;
	padding: 20px;
	display: flex;
	align-items: center;
	gap: 20px;
	position: relative;
	overflow: hidden;
	transition: all 0.4s ease;
}

.service-row::before {
	content: '';
	position: absolute;
	top: 0;
	left: 0;
	right: 0;
	height: 1px;
	background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.15), transparent);
}

.service-row::after {
	content: '';
	position: absolute;
	left: 0;
	top: 0;
	bottom: 0;
	width: 4px;
	background: linear-gradient(180deg, var(--primary), var(--accent));
	border-radius: 20px 0 0 20px;
	opacity: 0;
	transition: opacity 0.3s ease;
}

.service-row:hover {
	transform: translateY(-5px);
	background: rgba(255, 255, 255, 0.05);
	border-color: rgba(0, 240, 255, 0.2);
	box-shadow: 0 15px 40px rgba(0, 0, 0, 0.3);
}

.service-row:hover::after {
	opacity: 1;
}

.service-row-icon {
	width: 240px;
	height: 180px;
	min-width: 140px;
	border-radius: 16px;
	background: linear-gradient(135deg, rgba(0, 240, 255, 0.1), rgba(157, 78, 221, 0.1));
	border: 1px solid rgba(255, 255, 255, 0.08);
	display: flex;
	justify-content: center;
	align-items: center;
	position: relative;
	overflow: hidden;
}

.service-row-icon::before {
	content: '';
	position: absolute;
	top: 2px;
	left: 10%;
	right: 10%;
	height: 40%;
	background: linear-gradient(180deg, rgba(255, 255, 255, 0.2) 0%, transparent 100%);
	border-radius: 12px 12px 50% 50%;
}

.service-row-icon img {
	width: 100%;
	height: 100%;
	object-fit: cover;
	border-radius: 14px;
}

.service-row-content {
	flex: 1;
}

.service-row-content h4 {
	font-family: 'Syne', sans-serif;
	font-size: 18px;
	font-weight: 500;
	margin-bottom: 8px;
	color: var(--primary);
}

.service-row-content p {
	font-size: 13px;
	color: rgba(255, 255, 255, 0.6);
	line-height: 1.6;
}

.service-row-arrow {
	display: none;
}

/* Tabs */
.tabs-container {
	margin-bottom: 30px;
}

.tab-buttons {
	display: flex;
	justify-content: center;
	gap: 10px;
	flex-wrap: wrap;
	margin-bottom: 30px;
}

.tab-btn {
	padding: 12px 28px;
	background: var(--glass-bg);
	backdrop-filter: blur(20px);
	-webkit-backdrop-filter: blur(20px);
	border: 1px solid var(--glass-border);
	border-radius: 50px;
	color: rgba(255, 255, 255, 0.6);
	font-family: 'Outfit', sans-serif;
	font-size: 13px;
	letter-spacing: 1px;
	cursor: pointer;
	transition: all 0.3s ease;
	position: relative;
	overflow: hidden;
}

.tab-btn::before {
	content: '';
	position: absolute;
	top: 0;
	left: 0;
	right: 0;
	height: 50%;
	background: linear-gradient(180deg, rgba(255, 255, 255, 0.08) 0%, transparent 100%);
	border-radius: 50px 50px 0 0;
}

.tab-btn:hover {
	background: rgba(255, 255, 255, 0.05);
	color: #ffffff;
}

.tab-btn.active {
	background: linear-gradient(135deg, rgba(0, 240, 255, 0.2), rgba(255, 0, 212, 0.2));
	border-color: var(--primary);
	color: var(--primary);
	box-shadow: 0 0 20px var(--glow-cyan);
}

.tab-pane {
	display: none;
}

.tab-pane.active {
	display: block;
	animation: tabFade 0.4s ease-out;
}

@keyframes tabFade {
	from {
		opacity: 0;
		transform: translateY(20px);
	}

	to {
		opacity: 1;
		transform: translateY(0);
	}
}

/* Gallery */
.gallery-grid {
	display: grid;
	grid-template-columns: repeat(3, 1fr);
	gap: 20px;
}

.gallery-item {
	position: relative;
	border-radius: 16px;
	overflow: hidden;
	aspect-ratio: 1;
	cursor: pointer;
	background: var(--glass-bg);
	border: 1px solid var(--glass-border);
	transition: all 0.4s ease;
}

.gallery-item img {
	width: 100%;
	height: 100%;
	object-fit: cover;
	transition: transform 0.5s ease;
}

.gallery-item:hover {
	transform: scale(1.02);
	box-shadow: 0 20px 40px rgba(0, 0, 0, 0.4);
	border-color: var(--primary);
}

.gallery-item:hover img {
	transform: scale(1.1);
}

.gallery-overlay {
	position: absolute;
	inset: 0;
	background: linear-gradient(transparent 40%, rgba(10, 10, 18, 0.9) 100%);
	display: flex;
	flex-direction: column;
	justify-content: flex-end;
	padding: 20px;
	opacity: 0;
	transition: opacity 0.3s ease;
}

.gallery-item:hover .gallery-overlay {
	opacity: 1;
}

.gallery-overlay h4 {
	font-family: 'Syne', sans-serif;
	font-size: 16px;
	color: var(--primary);
	margin-bottom: 5px;
}

.gallery-overlay p {
	font-size: 12px;
	color: rgba(255, 255, 255, 0.6);
}

/* Filter Buttons */
.filter-buttons {
	display: flex;
	justify-content: center;
	gap: 10px;
	margin-bottom: 30px;
	flex-wrap: wrap;
}

.filter-btn {
	padding: 10px 20px;
	background: transparent;
	border: 1px solid var(--glass-border);
	border-radius: 30px;
	color: rgba(255, 255, 255, 0.6);
	font-family: 'Outfit', sans-serif;
	font-size: 12px;
	letter-spacing: 1px;
	cursor: pointer;
	transition: all 0.3s ease;
}

.filter-btn:hover,
.filter-btn.active {
	background: rgba(0, 240, 255, 0.1);
	border-color: var(--primary);
	color: var(--primary);
}

/* Testimonials */
.testimonials-grid {
	display: grid;
	grid-template-columns: repeat(2, 1fr);
	gap: 25px;
}

.testimonial-card {
	background: var(--glass-bg);
	backdrop-filter: blur(20px);
	-webkit-backdrop-filter: blur(20px);
	border: 1px solid var(--glass-border);
	border-radius: 20px;
	padding: 30px;
	position: relative;
	overflow: hidden;
}

.testimonial-card::before {
	content: '"';
	position: absolute;
	top: 20px;
	right: 30px;
	font-family: 'Syne', sans-serif;
	font-size: 80px;
	color: rgba(0, 240, 255, 0.1);
	line-height: 1;
}

.testimonial-text {
	font-size: 15px;
	line-height: 1.8;
	color: rgba(255, 255, 255, 0.7);
	margin-bottom: 20px;
	font-style: italic;
}

.testimonial-author {
	display: flex;
	align-items: center;
	gap: 15px;
}

.author-avatar {
	width: 70px;
	height: 70px;
	border-radius: 50%;
	overflow: hidden;
	border: 2px solid var(--primary);
	box-shadow: 0 0 20px rgba(0, 240, 255, 0.2);
}

.author-avatar img {
	width: 100%;
	height: 100%;
	object-fit: cover;
}

.author-info h5 {
	font-family: 'Syne', sans-serif;
	font-size: 14px;
	font-weight: 500;
	color: var(--primary);
}

.author-info p {
	font-size: 12px;
	color: rgba(255, 255, 255, 0.5);
}

/* About Section */
.about-content {
	display: grid;
	grid-template-columns: 1fr 1fr;
	gap: 40px;
	align-items: center;
}

.about-text h3 {
	font-family: 'Syne', sans-serif;
	font-size: 28px;
	font-weight: 500;
	margin-bottom: 20px;
	color: var(--primary);
}

.about-text p {
	color: rgba(255, 255, 255, 0.7);
	line-height: 1.8;
	margin-bottom: 15px;
}

.about-text a {
    color: var(--primary);
    text-decoration: none;
    position: relative;
    padding-bottom: 2px;
    transition: all 0.3s ease;
}

.about-text a::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 0;
    width: 0;
    height: 1px;
    background: linear-gradient(90deg, var(--primary), var(--accent));
    transition: width 0.3s ease;
}

.about-text a:hover {
    color: #ffffff;
    text-shadow: 0 0 10px rgba(0, 240, 255, 0.5);
}

.about-text a:hover::after {
    width: 100%;
}

.about-image {
	position: relative;
	border-radius: 20px;
	overflow: hidden;
}

.about-image img {
	width: 100%;
	height: auto;
	display: block;
}

.about-image::after {
	content: '';
	position: absolute;
	inset: 0;
	background: linear-gradient(135deg, rgba(0, 240, 255, 0.1), rgba(157, 78, 221, 0.1));
}

/* Contact Form */
.contact-grid {
	display: grid;
	grid-template-columns: 1fr 1fr;
	gap: 40px;
}

.contact-form {
	display: flex;
	flex-direction: column;
	gap: 20px;
}

.form-group {
	position: relative;
}

.form-group input,
.form-group textarea {
	width: 100%;
	padding: 16px 20px;
	background: var(--glass-bg);
	backdrop-filter: blur(20px);
	-webkit-backdrop-filter: blur(20px);
	border: 1px solid var(--glass-border);
	border-radius: 12px;
	color: #ffffff;
	font-family: 'Outfit', sans-serif;
	font-size: 14px;
	transition: all 0.3s ease;
}

.form-group input::placeholder,
.form-group textarea::placeholder {
	color: rgba(255, 255, 255, 0.4);
}

.form-group input:focus,
.form-group textarea:focus {
	outline: none;
	border-color: var(--primary);
	box-shadow: 0 0 20px var(--glow-cyan);
}

.form-group textarea {
	min-height: 150px;
	resize: vertical;
}

.submit-btn {
	padding: 16px 40px;
	background: var(--glass-bg);
	backdrop-filter: blur(20px);
	-webkit-backdrop-filter: blur(20px);
	border: 1px solid var(--glass-border);
	border-radius: 50px;
	color: var(--primary);
	font-family: 'Syne', sans-serif;
	font-size: 14px;
	font-weight: 600;
	letter-spacing: 2px;
	cursor: pointer;
	transition: all 0.3s ease;
	position: relative;
	overflow: hidden;
}

.submit-btn::before {
	content: '';
	position: absolute;
	top: 0;
	left: 0;
	right: 0;
	height: 50%;
	background: linear-gradient(180deg, rgba(255, 255, 255, 0.1) 0%, transparent 100%);
	border-radius: 50px 50px 0 0;
}

.submit-btn:hover {
	background: rgba(0, 240, 255, 0.1);
	border-color: var(--primary);
	transform: translateY(-3px);
	box-shadow:
		0 15px 30px rgba(0, 0, 0, 0.3),
		0 0 30px rgba(0, 200, 220, 0.25);
}

.contact-info {
	display: flex;
	flex-direction: column;
	gap: 25px;
}

.contact-item {
	background: var(--glass-bg);
	backdrop-filter: blur(20px);
	-webkit-backdrop-filter: blur(20px);
	border: 1px solid var(--glass-border);
	border-radius: 16px;
	padding: 25px;
	display: flex;
	align-items: center;
	gap: 20px;
	transition: all 0.3s ease;
}

.contact-item:hover {
	border-color: var(--primary);
	box-shadow: 0 10px 30px rgba(0, 0, 0, 0.2);
}

.contact-icon {
	width: 50px;
	height: 50px;
	border-radius: 50%;
	background: linear-gradient(135deg, rgba(0, 240, 255, 0.2), rgba(157, 78, 221, 0.2));
	display: flex;
	justify-content: center;
	align-items: center;
	font-size: 20px;
	color: var(--primary);
	position: relative;
	overflow: hidden;
}

.contact-icon::before {
	content: '';
	position: absolute;
	top: 2px;
	left: 10%;
	right: 10%;
	height: 40%;
	background: linear-gradient(180deg, rgba(255, 255, 255, 0.3) 0%, transparent 100%);
	border-radius: 50%;
}

.contact-details h4 {
	font-family: 'Syne', sans-serif;
	font-size: 14px;
	font-weight: 500;
	color: rgba(255, 255, 255, 0.5);
	margin-bottom: 5px;
}

.contact-details p {
	color: #ffffff;
	font-size: 15px;
}

/* Exit animations */
.menu-item.exit-up {
	animation: exitDown 0.5s ease-out forwards !important;
	pointer-events: none;
}

@keyframes exitDown {
	to {
		transform: translateY(50px);
		opacity: 0;
	}
}

.menu-item.return {
	animation: menuReturn 0.4s ease-out forwards !important;
}

@keyframes menuReturn {
	from {
		opacity: 0;
		transform: translateY(30px) scale(0.9);
	}

	to {
		opacity: 1;
		transform: translateY(0) scale(1);
	}
}

/* Footer */
.footer {
	margin-top: auto;
	padding: 30px 0;
	text-align: center;
	opacity: 0;
	animation: fadeUp 0.5s ease-out 1.7s forwards;
}

.footer p {
	font-size: 12px;
	color: rgba(255, 255, 255, 0.4);
	letter-spacing: 1px;
}

.footer a {
	color: var(--primary);
	text-decoration: none;
	transition: color 0.3s ease;
}

.footer a:hover {
	color: var(--secondary);
}

/* Responsive Design */
@media (max-width: 992px) {
	.menu-grid {
		grid-template-columns: repeat(3, 170px);
	}

	.menu-item {
		height: 145px;
	}

	.intro-hero {
		grid-template-columns: 1fr;
		gap: 40px;
	}

	.intro-hero-content {
		text-align: center;
		max-width: 100%;
	}

	.intro-cta-group {
		justify-content: center;
	}

	.intro-hero-visual {
		height: 300px;
	}

	.intro-metrics {
		flex-wrap: wrap;
		gap: 30px;
	}

	.metric-divider {
		display: none;
	}

	.intro-values {
		grid-template-columns: 1fr;
	}

	.services-list {
		grid-template-columns: 1fr;
	}

	.gallery-grid {
		grid-template-columns: repeat(2, 1fr);
	}

	.about-content,
	.contact-grid {
		grid-template-columns: 1fr;
	}
}

@media (max-width: 768px) {
	.brand-name {
		font-size: 36px;
		letter-spacing: 4px;
	}

	.menu-grid {
		grid-template-columns: repeat(2, 155px);
		gap: 15px;
	}

	.menu-item {
		height: 135px;
	}

	.menu-badge {
		width: 50px;
		height: 50px;
		font-size: 18px;
	}

	.section-title {
		font-size: 28px;
	}

	.intro-headline {
		font-size: 36px;
	}

	.intro-hero-visual {
		display: none;
	}

	.intro-metrics {
		padding: 30px 25px;
	}

	.metric-value {
		font-size: 32px;
	}

	.service-row {
		flex-direction: column;
		text-align: center;
	}

	.service-row-icon {
		width: 200px;
		height: 150px;
		min-width: 120px;
	}

	.testimonials-grid {
		grid-template-columns: 1fr;
	}

	.section-header-small {
		position: relative;
		top: auto;
		left: auto;
		margin-bottom: 20px;
		justify-content: center;
	}

	.back-btn {
		position: relative;
		top: auto;
		right: auto;
		display: block;
		width: fit-content;
		margin: 0 auto 30px;
	}

	.content-section {
		padding-top: 20px;
	}
}

@media (max-width: 480px) {
	.container {
		padding: 20px 15px;
	}

	.brand-name {
		font-size: 28px;
		letter-spacing: 3px;
	}

	.tagline {
		font-size: 10px;
		letter-spacing: 3px;
	}

	.menu-grid {
		grid-template-columns: repeat(2, 130px);
		gap: 12px;
	}

	.menu-item {
		height: 120px;
	}

	.menu-badge {
		width: 45px;
		height: 45px;
		font-size: 16px;
	}

	.menu-title {
		font-size: 10px;
		letter-spacing: 2px;
	}

	.intro-headline {
		font-size: 28px;
	}

	.intro-subtext {
		font-size: 15px;
	}

	.intro-cta-group {
		flex-direction: column;
		align-items: center;
	}

	.intro-cta-primary,
	.intro-cta-secondary {
		width: 100%;
		max-width: 250px;
		text-align: center;
	}

	.intro-metrics {
		flex-direction: column;
		gap: 25px;
	}

	.metric-value {
		font-size: 36px;
	}

	.gallery-grid {
		grid-template-columns: 1fr;
	}

	.tab-buttons {
		flex-direction: column;
		align-items: center;
	}

	.tab-btn {
		width: 100%;
		max-width: 250px;
	}
}
